// Node-RED Function Node : Poll stat 1-15 Pylontech
// Boucle stat 1 à 15 + \n pour envoi sériel
// Sortie 0 → serial-in | topic "pylontech_stat_loop"

let cmd = '';
for (let i = 1; i <= 15; i++) {
    cmd += `stat ${i}\n`;
}

msg.payload = cmd;
msg.topic = "pylontech_stat_loop";
return msg;

// Nœud Cycles amélioré (input serial lines)
if (msg.payload.includes("CYCLE Times")) {
    let match = msg.payload.match(/CYCLE Times : (\\d+)/);
    if (match) {
        let batId = flow.get("current_stat_id") || 1;  // Track via topic
        let cycles = parseInt(match[1]);
        global.set(`pylontech_bat${batId}_cycles`, cycles);
        msg.payload = {bat: batId, cycles};
        flow.set("current_stat_id", batId + 1);
    }
    return msg;
}
return null;

// ========== INITIALISATION AU DÉMARRAGE NODE-RED ==========
flow.set('pylontech_discoverySent', false);
flow.set('pylontech_lastBattCount', 0);
node.warn('⚡ Pylontech – Variables discovery réinitialisées au boot');
node.status({ fill: 'green', shape: 'dot', text: 'Discovery reset OK' });
return null;

if (flow.get('pylonBatScanning')) {
    node.warn('⚠️ Bat CSV scan actif – DATA scan ignoré');
    return null;
}
// Scan DATA : pwr + stat (données temps réel)
flow.set('pylonBuffer', '');
flow.set('pylonIndex', 1);
flow.set('pylonCmdIndex', 0);
flow.set('pylonBatteries', {});
flow.set('pylonScanning', true);

const COMMANDS = [
    { cmd: 'pwr',  label: 'Power Data' },
    { cmd: 'stat', label: 'Statistics' }
];

flow.set('pylonCommands', COMMANDS);
node.status({ fill: 'blue', shape: 'dot', text: 'Scan DATA – Bat 1 pwr...' });

msg.payload = 'pwr 1\n';
msg.scanCommands = COMMANDS;
return msg;

if (flow.get('pylonBatScanning')) {
    node.warn('⚠️ Bat CSV scan actif – INFO scan ignoré');
    return null;
}
// Scan INFO : info seulement (données système)
flow.set('pylonBuffer', '');
flow.set('pylonIndex', 1);
flow.set('pylonCmdIndex', 0);
flow.set('pylonBatteries', {});
flow.set('pylonScanning', true);

const COMMANDS = [
    { cmd: 'info', label: 'System Info' }
];

node.status({ fill: 'blue', shape: 'dot', text: 'Scan INFO – Bat 1 info...' });

flow.set('pylonCommands', COMMANDS);
msg.payload = 'info 1\n';
msg.scanCommands = COMMANDS;
return msg;

// ========== PYLONTECH – PROCESS RESPONSE V2.2 ==========
// Architecture multi-commandes avec scans séparés
// Supporte : pwr, stat, info (scan indépendants)
// =======================================================

// Ignorer si pas de scan en cours
if (!flow.get('pylonScanning')) return null;

// -----------------------------------------------------------------------
// 1. RÉCUPÉRATION DE LA CONFIGURATION DU SCAN EN COURS
// -----------------------------------------------------------------------
// Les COMMANDS sont passées par le nœud "Start Scan" dans msg.scanCommands
const COMMANDS = flow.get('pylonCommands') || [
    { cmd: 'pwr',  label: 'Power Data' },
    { cmd: 'stat', label: 'Statistics' }
];

// -----------------------------------------------------------------------
// 2. ACCUMULATEUR & CONTEXTE
// -----------------------------------------------------------------------
let buffer       = flow.get('pylonBuffer')     || '';
let index        = flow.get('pylonIndex')      || 1;
let cmdIndex     = flow.get('pylonCmdIndex')   || 0;
let batteries    = flow.get('pylonBatteries')  || {};

buffer += msg.payload;
flow.set('pylonBuffer', buffer);

// Attendre la fin de réponse
if (!buffer.includes('$$')) return null;

// Réponse complète reçue
const currentCmd = COMMANDS[cmdIndex].cmd;
flow.set('pylonBuffer', '');

// -----------------------------------------------------------------------
// 3. DÉTECTION BATTERIE ABSENTE
// -----------------------------------------------------------------------
const notPresent = buffer.includes('is not present') ||
                   buffer.includes('Invalid command or fail') ||
                   buffer.includes('Target device is not present');

if (notPresent) {
    // Fin du scan → publier tout
    flow.set('pylonScanning', false);
    const count = Object.keys(batteries).length;

    // Agrégats globaux
    let totalVoltage = 0, totalCurrent = 0, totalCapacity = 0, minSoc = 100, maxSoc = 0;
    for (const b of Object.values(batteries)) {
        const pwr = b.pwr || {};
        if (pwr.voltage_V)     totalVoltage  += pwr.voltage_V;
        if (pwr.current_A)     totalCurrent  += pwr.current_A;
        if (pwr.capacity_mAh)  totalCapacity += pwr.capacity_mAh;
        if (pwr.soc_percent !== null && pwr.soc_percent !== undefined) {
            if (pwr.soc_percent < minSoc) minSoc = pwr.soc_percent;
            if (pwr.soc_percent > maxSoc) maxSoc = pwr.soc_percent;
        }
    }

    const result = {
        timestamp     : new Date().toISOString(),
        battery_count : count,
        summary: {
            avg_voltage_V      : count ? +(totalVoltage  / count).toFixed(3) : null,
            total_current_A    : +totalCurrent.toFixed(3),
            total_capacity_mAh : totalCapacity,
            min_soc_percent    : minSoc,
            max_soc_percent    : maxSoc,
            total_power_W      : count ? +((totalVoltage / count) * totalCurrent).toFixed(1) : null
        },
        batteries: batteries
    };

    const scanType = COMMANDS[0].cmd === 'info' ? 'INFO' : 'DATA';
    node.status({ fill: 'green', shape: 'dot', text: `OK ${scanType} – ${count} bat. @ ${new Date().toLocaleTimeString()}` });
    return [null, { payload: result, topic: 'pylontech/status' }];
}

// -----------------------------------------------------------------------
// 4. PARSERS PAR COMMANDE
// -----------------------------------------------------------------------

// Utilitaire extraction regex
function extract(pattern) {
    const m = buffer.match(pattern);
    return m ? m[1].trim() : null;
}
function extractInt(pattern) {
    const v = extract(pattern);
    return v !== null ? parseInt(v, 10) : null;
}

// --- PARSER : pwr ---
function parsePwr() {
    const voltage_mV  = extractInt(/Voltage\s*:\s*(\d+)\s*mV/);
    const current_mA  = extractInt(/Current\s*:\s*(-?\d+)\s*mA/);
    const temp_mC     = extractInt(/Temperature\s*:\s*(\d+)\s*mC/);
    const soc         = extractInt(/Coulomb\s*:\s*(\d+)\s*%/);
    const capacity_mAh= extractInt(/Total Coulomb\s*:\s*(\d+)\s*mAH/);
    const maxVolt_mV  = extractInt(/Max Voltage\s*:\s*(\d+)\s*mV/);
    const cycles      = extractInt(/Charge Times\s*:\s*(\d+)/);

    return {
        voltage_V        : voltage_mV  !== null ? +(voltage_mV  / 1000).toFixed(3) : null,
        current_A        : current_mA  !== null ? +(current_mA  / 1000).toFixed(3) : null,
        temperature_C    : temp_mC     !== null ? +(temp_mC     / 1000).toFixed(1) : null,
        soc_percent      : soc,
        capacity_mAh     : capacity_mAh,
        max_voltage_V    : maxVolt_mV  !== null ? +(maxVolt_mV  / 1000).toFixed(3) : null,
        charge_cycles    : cycles,
        power_W          : (voltage_mV !== null && current_mA !== null)
                            ? +((voltage_mV / 1000) * (current_mA / 1000)).toFixed(1)
                            : null,
        status_basic        : extract(/Basic Status\s*:\s*(\w+)/),
        status_voltage      : extract(/Volt Status\s*:\s*(\w+)/),
        status_current      : extract(/Current Status\s*:\s*(\w+)/),
        status_temperature  : extract(/Tmpr\.\s*Status\s*:\s*(\w+)/),
        status_coulomb      : extract(/Coul\.\s*Status\s*:\s*(\w+)/),
        status_soh          : extract(/Soh\.\s*Status\s*:\s*(\w+)/),
        heater_status       : extract(/Heater Status\s*:\s*(\w+)/),
        bat_events          : extract(/Bat Events\s*:\s*(0x[0-9a-fA-F]+)/),
        power_events        : extract(/Power Events\s*:\s*(0x[0-9a-fA-F]+)/),
        system_fault        : extract(/System Fault\s*:\s*(0x[0-9a-fA-F]+)/)
    };
}

// --- PARSER : stat ---
function parseStat() {
    return {
        device_address      : extractInt(/Device address\s+(\d+)/),
        data_items          : extractInt(/Data Items\s*:\s*(\d+)/),
        hisdata_items       : extractInt(/HisData Items\s*:\s*(\d+)/),
        charge_count        : extractInt(/Charge Cnt\.\s*:\s*(\d+)/),
        discharge_count     : extractInt(/Discharge Cnt\.\s*:\s*(\d+)/),
        charge_times        : extractInt(/Charge Times\s*:\s*(\d+)/),
        status_count        : extractInt(/Status Cnt\.\s*:\s*(\d+)/),
        idle_times          : extractInt(/Idle Times\s*:\s*(\d+)/),
        coc_times           : extractInt(/COC Times\s*:\s*(\d+)/),
        coc2_times          : extractInt(/COC2 Times\s*:\s*(\d+)/),
        doc_times           : extractInt(/DOC Times\s*:\s*(\d+)/),
        doc2_times          : extractInt(/DOC2 Times\s*:\s*(\d+)/),
        coca_times          : extractInt(/COCA Times\s*:\s*(\d+)/),
        doca_times          : extractInt(/DOCA Times\s*:\s*(\d+)/),
        sc_times            : extractInt(/SC Times\s*:\s*(\d+)/),
        bat_ov_times        : extractInt(/Bat OV Times\s*:\s*(\d+)/),
        bat_hv_times        : extractInt(/Bat HV Times\s*:\s*(\d+)/),
        bat_lv_times        : extractInt(/Bat LV Times\s*:\s*(\d+)/),
        bat_uv_times        : extractInt(/Bat UV Times\s*:\s*(\d+)/),
        bat_slp_times       : extractInt(/Bat SLP Times\s*:\s*(\d+)/),
        pwr_ov_times        : extractInt(/Pwr OV Times\s*:\s*(\d+)/),
        pwr_hv_times        : extractInt(/Pwr HV Times\s*:\s*(\d+)/),
        pwr_lv_times        : extractInt(/Pwr LV Times\s*:\s*(\d+)/),
        pwr_uv_times        : extractInt(/Pwr UV Times\s*:\s*(\d+)/),
        pwr_slp_times       : extractInt(/Pwr SLP Times\s*:\s*(\d+)/),
        cot_times           : extractInt(/COT Times\s*:\s*(\d+)/),
        cut_times           : extractInt(/CUT Times\s*:\s*(\d+)/),
        dot_times           : extractInt(/DOT Times\s*:\s*(\d+)/),
        dut_times           : extractInt(/DUT Times\s*:\s*(\d+)/),
        cht_times           : extractInt(/CHT Times\s*:\s*(\d+)/),
        clt_times           : extractInt(/CLT Times\s*:\s*(\d+)/),
        dht_times           : extractInt(/DHT Times\s*:\s*(\d+)/),
        dlt_times           : extractInt(/DLT Times\s*:\s*(\d+)/),
        shut_times          : extractInt(/Shut Times\s*:\s*(\d+)/),
        reset_times         : extractInt(/Reset Times\s*:\s*(\d+)/),
        rv_times            : extractInt(/RV Times\s*:\s*(\d+)/),
        input_ov_times      : extractInt(/Input OV Times\s*:\s*(\d+)/),
        soh_times           : extractInt(/SOH Times\s*:\s*(\d+)/),
        bmicerr_times       : extractInt(/BMICERR Times\s*:\s*(\d+)/),
        cycle_times         : extractInt(/CYCLE Times\s*:\s*(\d+)/),
        soh_percent         : extractInt(/SOH\s*:\s*(\d+)/),
        pwr_percent         : extractInt(/Pwr Percent\s*:\s*(\d+)/),
        pwr_coulomb         : extractInt(/Pwr Coulomb\s*:\s*(\d+)/),
        dsg_cap             : extractInt(/Dsg Cap\s*:\s*(\d+)/),
        ht_05c_count        : extractInt(/HT@0\.5C Cnt\s*:\s*(\d+)/),
        lt_05c_count        : extractInt(/LT@0\.5C Cnt\s*:\s*(\d+)/),
        ht_count            : extractInt(/HT Cnt\s*:\s*(\d+)/),
        lt_count            : extractInt(/LT Cnt\s*:\s*(\d+)/),
        lv_count            : extractInt(/LV Cnt\s*:\s*(\d+)/),
        lifewarn_times      : extractInt(/LifeWarn Times\s*:\s*(\d+)/),
        lifealarm_times     : extractInt(/LifeAlarm Times\s*:\s*(\d+)/)
    };
}

// --- PARSER : info ---
function parseInfo() {
    const maxDischgStr = extract(/Max Dischg Curr\s*:\s*(-?\d+)mA/);
    const maxChargeStr = extract(/Max Charge Curr\s*:\s*(\d+)mA/);

    return {
        device_address       : extractInt(/Device address\s*:\s*(\d+)/),
        manufacturer         : extract(/Manufacturer\s*:\s*(.+)/),
        device_name          : extract(/Device name\s*:\s*(.+)/),
        board_version        : extract(/Board version\s*:\s*(.+)/),
        board                : extract(/Board\s*:\s*(.+)/),
        main_soft_version    : extract(/Main Soft version\s*:\s*(.+)/),
        soft_version         : extract(/Soft version\s*:\s*(.+)/),
        boot_version         : extract(/Boot version\s*:\s*(.+)/),
        comm_version         : extract(/Comm version\s*:\s*(.+)/),
        release_date         : extract(/Release Date\s*:\s*(.+)/),
        barcode              : extract(/Barcode\s*:\s*(.+)/),
        specification        : extract(/Specification\s*:\s*(.+)/),
        cell_number          : extractInt(/Cell Number\s*:\s*(\d+)/),
        max_discharge_curr_A : maxDischgStr ? +(parseInt(maxDischgStr, 10) / 1000).toFixed(1) : null,
        max_charge_curr_A    : maxChargeStr ? +(parseInt(maxChargeStr, 10) / 1000).toFixed(1) : null,
        epon_port_rate       : extractInt(/EPONPort rate\s*:\s*(\d+)/),
        console_port_rate    : extractInt(/Console Port rate\s*:\s*(\d+)/)
    };
}

// Routeur de parsers
const PARSERS = {
    pwr  : parsePwr,
    stat : parseStat,
    info : parseInfo
};

// -----------------------------------------------------------------------
// 5. STOCKAGE DES DONNÉES
// -----------------------------------------------------------------------
const batKey = `battery_${index}`;
if (!batteries[batKey]) {
    batteries[batKey] = { index: index };
}

// Parser et stocker dans un sous-objet
const parsed = PARSERS[currentCmd]();
batteries[batKey][currentCmd] = parsed;

flow.set('pylonBatteries', batteries);

// -----------------------------------------------------------------------
// 6. LOGIQUE DE BOUCLE : commande suivante ou batterie suivante
// -----------------------------------------------------------------------
const nextCmdIndex = cmdIndex + 1;

if (nextCmdIndex < COMMANDS.length) {
    // Commande suivante pour la même batterie
    flow.set('pylonCmdIndex', nextCmdIndex);
    const nextCmd = COMMANDS[nextCmdIndex].cmd;
    node.status({ fill: 'blue', shape: 'dot', text: `Bat ${index} – ${COMMANDS[nextCmdIndex].label}...` });
    return [{ payload: `${nextCmd} ${index}\n`, scanCommands: COMMANDS }, null];
} else {
    // Toutes les commandes exécutées → batterie suivante
    flow.set('pylonCmdIndex', 0);
    const nextIndex = index + 1;

    if (nextIndex <= 16) {
        flow.set('pylonIndex', nextIndex);
        node.status({ fill: 'blue', shape: 'dot', text: `Bat ${nextIndex} – ${COMMANDS[0].label}...` });
        return [{ payload: `${COMMANDS[0].cmd} ${nextIndex}\n`, scanCommands: COMMANDS }, null];
    } else {
        // Toutes les batteries scannées (cas max 16 atteint)
        flow.set('pylonScanning', false);
        const count = Object.keys(batteries).length;

        // Agrégats
        let totalVoltage = 0, totalCurrent = 0, totalCapacity = 0, minSoc = 100, maxSoc = 0;
        for (const b of Object.values(batteries)) {
            const pwr = b.pwr || {};
            if (pwr.voltage_V)     totalVoltage  += pwr.voltage_V;
            if (pwr.current_A)     totalCurrent  += pwr.current_A;
            if (pwr.capacity_mAh)  totalCapacity += pwr.capacity_mAh;
            if (pwr.soc_percent !== null && pwr.soc_percent !== undefined) {
                if (pwr.soc_percent < minSoc) minSoc = pwr.soc_percent;
                if (pwr.soc_percent > maxSoc) maxSoc = pwr.soc_percent;
            }
        }

        const result = {
            timestamp     : new Date().toISOString(),
            battery_count : count,
            summary: {
                avg_voltage_V      : count ? +(totalVoltage  / count).toFixed(3) : null,
                total_current_A    : +totalCurrent.toFixed(3),
                total_capacity_mAh : totalCapacity,
                min_soc_percent    : minSoc,
                max_soc_percent    : maxSoc,
                total_power_W      : count ? +((totalVoltage / count) * totalCurrent).toFixed(1) : null
            },
            batteries: batteries
        };
        node.warn("Commande active: " + currentCmd);
        const scanType = COMMANDS[0].cmd === 'info' ? 'INFO' : 'DATA';
        node.status({ fill: 'green', shape: 'dot', text: `OK ${scanType} – ${count} bat. @ ${new Date().toLocaleTimeString()}` });
        return [null, { payload: result, topic: 'pylontech/status' }];
    }
}

// ========== PYLONTECH – MQTT DISCOVERY V3 – AVEC STAT ==========
// ✓ Support multi-commandes (pwr + stat)
// ✓ Noms d'entités sans doublon
// ©JLM 2025-2026
// ================================================================

const payload            = msg.payload;
const discoveryPrefix    = "homeassistant";
const deviceManufacturer = "Smartphoton / ©JLM 2026";
const swVersion          = "2.1";

// -----------------------------------------------------------------------
// SCHÉMAS CAPTEURS PAR BATTERIE
// -----------------------------------------------------------------------

// Capteurs PWR (mesures en temps réel)
const PWR_SENSORS = {
