    power_W:       { device_class: "power",          unit: "W",   state_class: "measurement",      icon: "mdi:lightning-bolt" },
    temperature_C: { device_class: "temperature",    unit: "°C",  state_class: "measurement",      icon: "mdi:thermometer" },
