    reset_times:      { device_class: null,       unit: "",    state_class: "total_increasing", icon: "mdi:restart" },
    shut_times:       { device_class: null,       unit: "",    state_class: "total_increasing", icon: "mdi:power" },
    pwr_coulomb:      { device_class: null,       unit: "mAh", state_class: "total_increasing", icon: "mdi:battery-sync" },
    dsg_cap:          { device_class: null,       unit: "mAh", state_class: "total_increasing", icon: "mdi:battery-minus" }
};

