    barcode:              { icon: "mdi:barcode" },
    specification:        { icon: "mdi:information" }
};

const INFO_NUMERIC_SENSORS = {
    cell_number:          { icon: "mdi:counter", unit: "", state_class: "measurement" },
    max_discharge_curr_A: { icon: "mdi:current-dc", unit: "A", state_class: "measurement" },
    max_charge_curr_A:    { icon: "mdi:current-dc", unit: "A", state_class: "measurement" },
    epon_port_rate:       { icon: "mdi:network", unit: "bps", state_class: "measurement" },
    console_port_rate:    { icon: "mdi:console", unit: "bps", state_class: "measurement" }
};


// Résumé global
const SUMMARY_SENSORS = {
    avg_voltage_V:       { device_class: "voltage", unit: "V",   state_class: "measurement", icon: "mdi:flash" },
    total_current_A:     { device_class: "current", unit: "A",   state_class: "measurement", icon: "mdi:current-dc" },
    total_power_W:       { device_class: "power",   unit: "W",   state_class: "measurement", icon: "mdi:lightning-bolt" },
    total_capacity_mAh:  { device_class: null,      unit: "mAh", state_class: "measurement", icon: "mdi:battery-high" },
    min_soc_percent:     { device_class: "battery", unit: "%",   state_class: "measurement", icon: "mdi:battery-low" },
    max_soc_percent:     { device_class: "battery", unit: "%",   state_class: "measurement", icon: "mdi:battery" }
};

// -----------------------------------------------------------------------
// CONTEXTE & DÉTECTION CHANGEMENTS
// -----------------------------------------------------------------------
const discoverySentKey = "pylontech_discoverySent";
const lastBattCountKey = "pylontech_lastBattCount";

let discoverySent  = flow.get(discoverySentKey) || false;
let lastBattCount  = flow.get(lastBattCountKey) || 0;
const currentCount = payload.battery_count || 0;
const needsDiscovery = true;

if (!needsDiscovery) {
    node.debug(`⊘ Discovery: Aucun changement (${currentCount} batteries)`);
    return null;
}

// -----------------------------------------------------------------------
// UTILITAIRES
// -----------------------------------------------------------------------
function toLabel(key) {
    // Supprime le suffixe d'unité (ex: _V, _A, _W, _C) avant mise en forme
    return key.replace(/_[A-Za-z]$/, '').replace(/_/g, " ").replace(/\b\w/g, c => c.toUpperCase());
}

function toObjId(field) {
    // Supprime le suffixe d'unité (ex: _V, _A, _W, _C) pour l'id entité
    return field.replace(/_[A-Za-z]$/, '').toLowerCase();
}

function buildSensorConfig({ uniqueId, name, stateTopic, device,
                              deviceClass, unit, stateClass, icon, entityCategory }) {
    const cfg = { name, unique_id: uniqueId, state_topic: stateTopic, icon: icon || "mdi:information", device };
    if (deviceClass)    cfg.device_class        = deviceClass;
    if (unit)           cfg.unit_of_measurement = unit;
    if (stateClass)     cfg.state_class         = stateClass;
    if (entityCategory) cfg.entity_category     = entityCategory;
    return cfg;
}

