function buildBatteryMsgs(bat) {
    const idx       = bat.index;
    const deviceID  = `PYLONTECH_BATTERY_${idx}`;
    const baseTopic = `pylontech/battery/${idx}`;

    const device = {
        identifiers  : [deviceID],
        name         : `Pylontech Battery ${idx}`,
        manufacturer : deviceManufacturer,
        model        : "Pylontech US2000c / US3000 / US5000",
        sw_version   : swVersion,
        via_device   : "PYLONTECH_BATTERY_BANK"
    };

    const msgs = [];

    // --- PWR : mesures temps réel ---
    const pwr = bat.pwr || {};
    for (const [field, meta] of Object.entries(PWR_SENSORS)) {
        if (pwr[field] === null || pwr[field] === undefined) continue;
        const objId = toObjId(field);
        const cfgTopic = `${discoveryPrefix}/sensor/${deviceID}/pwr_${objId}/config`;
        const stTopic  = `${baseTopic}/pwr/${field}`;

        msgs.push({
            topic: cfgTopic,
            payload: JSON.stringify(buildSensorConfig({
                uniqueId: `${deviceID}_pwr_${objId}`, name: toLabel(field),
                stateTopic: stTopic, device, deviceClass: meta.device_class,
                unit: meta.unit, stateClass: meta.state_class, icon: meta.icon
            })),
            retain: true, qos: 0
        });
        msgs.push({ topic: stTopic, payload: String(pwr[field]), retain: true, qos: 0 });
    }

    // PWR texte (diagnostics)
    for (const [field, meta] of Object.entries(PWR_TEXT_SENSORS)) {
        if (pwr[field] === null || pwr[field] === undefined) continue;
        const objId = toObjId(field);
        const cfgTopic = `${discoveryPrefix}/sensor/${deviceID}/pwr_${objId}/config`;
        const stTopic  = `${baseTopic}/pwr/${field}`;

        msgs.push({
            topic: cfgTopic,
            payload: JSON.stringify(buildSensorConfig({
                uniqueId: `${deviceID}_pwr_${objId}`, name: toLabel(field),
                stateTopic: stTopic, device, icon: meta.icon, entityCategory: "diagnostic"
            })),
            retain: true, qos: 0
        });
        msgs.push({ topic: stTopic, payload: String(pwr[field]), retain: true, qos: 0 });
    }

    // --- STAT : statistiques & compteurs ---
    const stat = bat.stat || {};
    for (const [field, meta] of Object.entries(STAT_SENSORS)) {
        if (stat[field] === null || stat[field] === undefined) continue;
        const objId = toObjId(field);
        const cfgTopic = `${discoveryPrefix}/sensor/${deviceID}/stat_${objId}/config`;
        const stTopic  = `${baseTopic}/stat/${field}`;

        msgs.push({
            topic: cfgTopic,
            payload: JSON.stringify(buildSensorConfig({
                uniqueId: `${deviceID}_stat_${objId}`, name: `Stat ${toLabel(field)}`,
                stateTopic: stTopic, device, deviceClass: meta.device_class,
                unit: meta.unit, stateClass: meta.state_class, icon: meta.icon,
                entityCategory: "diagnostic"
            })),
            retain: true, qos: 0
        });
        msgs.push({ topic: stTopic, payload: String(stat[field]), retain: true, qos: 0 });
    }

    // STAT alarmes (compteurs d'événements)
    for (const [field, meta] of Object.entries(STAT_ALARM_SENSORS)) {
        if (stat[field] === null || stat[field] === undefined) continue;
        const objId = toObjId(field);
        const cfgTopic = `${discoveryPrefix}/sensor/${deviceID}/stat_${objId}/config`;
        const stTopic  = `${baseTopic}/stat/${field}`;

        msgs.push({
            topic: cfgTopic,
            payload: JSON.stringify(buildSensorConfig({
                uniqueId: `${deviceID}_stat_${objId}`, name: `Alarm ${toLabel(field)}`,
                stateTopic: stTopic, device, icon: meta.icon,
                stateClass: "total_increasing", entityCategory: "diagnostic"
            })),
            retain: true, qos: 0
        });
        msgs.push({ topic: stTopic, payload: String(stat[field]), retain: true, qos: 0 });
    }

    // --- INFO : informations système ---
    const info = bat.info || {};

    // INFO texte
    for (const [field, meta] of Object.entries(INFO_SENSORS)) {
        if (info[field] === null || info[field] === undefined) continue;
        const objId = toObjId(field);
        const cfgTopic = `${discoveryPrefix}/sensor/${deviceID}/info_${objId}/config`;
        const stTopic  = `${baseTopic}/info/${field}`;

        msgs.push({
            topic: cfgTopic,
            payload: JSON.stringify(buildSensorConfig({
                uniqueId: `${deviceID}_info_${objId}`, name: `Info ${toLabel(field)}`,
                stateTopic: stTopic, device, icon: meta.icon, entityCategory: "diagnostic"
            })),
            retain: true, qos: 0
        });
        msgs.push({ topic: stTopic, payload: String(info[field]), retain: true, qos: 0 });
    }

    // INFO numérique
    for (const [field, meta] of Object.entries(INFO_NUMERIC_SENSORS)) {
        if (info[field] === null || info[field] === undefined) continue;
        const objId = toObjId(field);
        const cfgTopic = `${discoveryPrefix}/sensor/${deviceID}/info_${objId}/config`;
        const stTopic  = `${baseTopic}/info/${field}`;

        msgs.push({
            topic: cfgTopic,
            payload: JSON.stringify(buildSensorConfig({
                uniqueId: `${deviceID}_info_${objId}`, name: `Info ${toLabel(field)}`,
                stateTopic: stTopic, device, icon: meta.icon,
                unit: meta.unit, stateClass: meta.state_class, entityCategory: "diagnostic"
            })),
            retain: true, qos: 0
        });
        msgs.push({ topic: stTopic, payload: String(info[field]), retain: true, qos: 0 });
    }


    return msgs;
}

