function buildSummaryMsgs(summary, count) {
    const deviceID  = "PYLONTECH_BATTERY_BANK";
    const baseTopic = "pylontech/summary";

    const device = {
        identifiers  : [deviceID],
        name         : "Pylontech Battery Bank",
        manufacturer : deviceManufacturer,
        model        : `Pack – ${count} module(s)`,
        sw_version   : swVersion
    };

    const msgs = [];

    // Nombre de batteries
    msgs.push({
        topic: `${discoveryPrefix}/sensor/${deviceID}/battery_count/config`,
        payload: JSON.stringify(buildSensorConfig({
            uniqueId: `${deviceID}_battery_count`, name: "Battery Count",
            stateTopic: `${baseTopic}/battery_count`, device,
            icon: "mdi:counter", stateClass: "measurement"
        })),
        retain: true, qos: 0
    });
    msgs.push({ topic: `${baseTopic}/battery_count`, payload: String(count), retain: true, qos: 0 });

    // Capteurs résumé
    for (const [field, meta] of Object.entries(SUMMARY_SENSORS)) {
        if (summary[field] === null || summary[field] === undefined) continue;
        const objId = toObjId(field);
        const cfgTopic = `${discoveryPrefix}/sensor/${deviceID}/${objId}/config`;
        const stTopic  = `${baseTopic}/${field}`;

        msgs.push({
            topic: cfgTopic,
            payload: JSON.stringify(buildSensorConfig({
                uniqueId: `${deviceID}_${objId}`, name: toLabel(field),
                stateTopic: stTopic, device, deviceClass: meta.device_class,
                unit: meta.unit, stateClass: meta.state_class, icon: meta.icon
            })),
            retain: true, qos: 0
        });
        msgs.push({ topic: stTopic, payload: String(summary[field]), retain: true, qos: 0 });
    }

    // Timestamp
    msgs.push({
        topic: `${discoveryPrefix}/sensor/${deviceID}/last_scan/config`,
        payload: JSON.stringify(buildSensorConfig({
            uniqueId: `${deviceID}_last_scan`, name: "Last Scan",
            stateTopic: `${baseTopic}/last_scan`, device,
            deviceClass: "timestamp", icon: "mdi:clock-check", entityCategory: "diagnostic"
        })),
        retain: true, qos: 0
    });
    msgs.push({
        topic: `${baseTopic}/last_scan`,
        payload: payload.timestamp || new Date().toISOString(),
        retain: true, qos: 0
    });

    return msgs;
}

