// --- Détecter module absent ---
const absent = buffer.includes('is not present') ||
               buffer.includes('Invalid command') ||
               buffer.includes('Target device is not present');

if (!absent) {
    // -------------------------------------------------------------------
    // PARSER COMPLET – ligne du tableau bat
    // Format Pylontech :
    // Battery  Volt  Curr  Tempr  Base State  Volt. State  Curr. State  Temp. State  SOC      Coulomb       BAL
    // 0        3321  0     9600   Idle        Normal       Normal       Normal       90%      44785 mAH     N
    // -------------------------------------------------------------------
    const lines = buffer.split('\n');
    let parsed = 0;

    for (const line of lines) {
        const clean = line.replace(/\r/g, '').trim();

        // Regex étendue : cell volt curr temp bState vState cState tState SOC% coulombMAH bal
        const m = clean.match(
            /^(\d+)\s+(-?\d+)\s+(-?\d+)\s+(\d+)\s+(\S+)\s+(\S+)\s+(\S+)\s+(\S+)\s+(-?\d+)%\s+(\d+)\s+mAH\s+(\S+)/i
        );

        if (m) {
            data.push({
                ts:       timestamp,
                mod:      module,
                cell:     parseInt(m[1]),
                volt:     parseInt(m[2]),   // mV
                curr:     parseInt(m[3]),   // mA
                temp:     parseInt(m[4]),   // m°C
                bState:   m[5],
                vState:   m[6],
                cState:   m[7],
                tState:   m[8],
                soc:      parseInt(m[9]),   // %
                coulomb:  parseInt(m[10]),  // mAh
                bal:      m[11]             // Y/N
            });
            parsed++;
        }
    }
    flow.set('pylonBatData', data);
    node.status({fill:'blue', shape:'dot',
        text:`Module ${module}/${maxModule} – ${parsed} cellules`});
}

// --- Module suivant ou fin ? ---
const nextModule = absent ? (maxModule + 1) : (module + 1);

if (nextModule <= maxModule) {
    flow.set('pylonBatModule', nextModule);
    node.status({fill:'blue', shape:'dot',
        text:`Module ${nextModule}/${maxModule}...`});
    return [{payload: `bat ${nextModule}\n`}, null, null];
}

