// -------------------------------------------------------------------
// CONSTRUCTION CSV
// - BOM UTF-8     : Excel reconnaît l'encodage
// - "sep=;"       : directive Excel pour forcer le séparateur ;
//                   (évite que la virgule décimale soit confondue
//                    avec un délimiteur de colonne)
// - Virgule ","   : séparateur décimal français
// -------------------------------------------------------------------
const SEP    = 'sep=;\n';
const BOM    = '\uFEFF';
const HEADER = 'Horodatage;Module;Cellule;Tension_V;Courant_A;Temperature_C;Etat_Base;Etat_Tension;Etat_Courant;Etat_Temp;SOC_pct;Coulomb_mAh;Equilibrage\n';

