    (d.temp / 1000).toFixed(1).replace('.', ','),
    d.bState,
    d.vState,
    d.cState,
    d.tState,
    d.soc,
    d.coulomb,
    d.bal
].join(';')).join('\n') + '\n';

const csvContent = BOM + SEP + HEADER + rows;

